CREATE OR REPLACE FUNCTION fpa_com_cal_agetext (adt_bdate timestamp(0), adt_edate timestamp(0),as_format char) RETURNS varchar AS $body$
DECLARE

  /*adt_bdate - วันที่เริ่มต้น ,adt_edate - วันที่สิ้นสุด ,[ as_format = 'YM' แสดง ปีเดือน ,  'YMD' แสดง ปีเดือนวัน]*/

  li_year integer := 0; --ปี
  li_month integer := 0;--เดือน
  li_date integer := 0;--วันที่
  ls_return varchar(100);--ผลลัพธ์
BEGIN
   if adt_edate > adt_bdate then
    -- ปี
     li_year :=  (pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)/12);
    --เดือน , วัน
      li_date := sign(date_trunc('day', adt_edate) - adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)*'1 month'::interval);
      if li_date = -1 then
         li_month := date_trunc('day', mod(months_between(adt_edate, adt_bdate),12))-1;
         li_date := 0;--เคีลยร์ค่า
         li_date := adt_edate - (adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)*'1 month'::interval-1);
      else
        li_month := date_trunc('day', mod(months_between(adt_edate, adt_bdate),12));
        li_date := 0;--เคีลยร์ค่า
        li_date := adt_edate - adt_bdate + pka_srv_datetime.fp_MonthsAfter(adt_bdate,adt_edate)*'1 month'::interval;
      end if;
   end if;
 -- การแสดงผล
 ls_return := ' ';
   if li_year > 0 then
      ls_return := ls_return||li_year::text||' ปี ';
   end if;
    if li_month > 0 then
      ls_return := ls_return||li_month::text||' เดือน ';
   end if;
   if trim(both as_format) = 'YM' then goto end_return;end if;
   if li_date > 0 then
      ls_return := ls_return||li_date::text||' วัน';
   end if;
  <<end_return>>


return trim(both ls_return);

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
